#!/usr/bin/env python3 """codegen — graph-ai.json IR → canonical Python source.  Key design:   - if/elif/else 链通过 edge.label == "orelse" 检测   - 函数参数名从 PortDef.name 还原   - 所有生成代码可运行、可读、可再次解析 """  from pathlib import Path from packages.graph_ir import Node, Edge, Graph, CATEGORY_ESCAPE  _INDENT = "    "  # Operator label → Python symbol _BINOP_SYM = {     "Add": "+", "Sub": "-", "Mult": "*", "Div": "/",     "FloorDiv": "//", "Mod": "%", "Pow": "**",     "LShift": "<<", "RShift": ">>",     "BitOr": "|", "BitXor": "^", "BitAnd": "&",     "And": "and", "Or": "or", } _UNARYOP_SYM = {"UAdd": "+", "USub": "-", "Not": "not ", "Invert": "~"}   class PythonGenerator:     """Convert a Graph IR back into canonical Python source."""      def __init__(self, ir: dict):         self.ir = ir         self.graph: Graph = Graph.from_dict(ir)         self._node_map: dict[str, Node] = {n.id: n for n in self.graph.nodes}         # Edges indexed by target (incoming to a node)         self._incoming: dict[str, list[Edge]] = {}         # Edges indexed by source (outgoing from a node), filtered by label         self._outgoing_body: dict[str, list[Edge]] = {}         self._outgoing_orelse: dict[str, list[Edge]] = {}         for e in self.graph.edges:             self._incoming.setdefault(e.target, []).append(e)             if e.label == "body":                 self._outgoing_body.setdefault(e.source, []).append(e)             elif e.label == "orelse":                 self._outgoing_orelse.setdefault(e.source, []).append(e)         self._out: list[str] = []         self._indent = 0      def _p(self, line: str = "", indent_delta: int = 0) -> None:         if indent_delta < 0:             self._indent += indent_delta         self._out.append(_INDENT * max(0, self._indent) + line)         if indent_delta > 0:             self._indent += indent_delta      # ── Helpers ────────────────────────────────────────────────────────────      def _get_incoming(self, node_id: str, port: str) -> str | None:         """Return source node ID of the edge arriving on `port`, or None."""         for e in self._incoming.get(node_id, []):             if e.targetPort == port:                 return e.source         return None      def _body_children(self, node_id: str) -> list[str]:         """Return IDs of body children (ordered by edge insertion)."""         edges = self._outgoing_body.get(node_id, [])         return [e.target for e in edges]      def _orelse_children(self, node_id: str) -> list[str]:         """Return IDs of orelse children (ordered by edge insertion)."""         edges = self._outgoing_orelse.get(node_id, [])         return [e.target for e in edges]      # ── Expression emitter ─────────────────────────────────────────────────      def _emit_expr(self, node_id: str) -> str:         n = self._node_map.get(node_id)         if not n:             return "?"          if n.type == "literal":             if n.value is None:                 return "None"             return repr(n.value)          if n.type == "name":             return str(n.value) if n.value else n.label          if n.type == "attribute":             obj_src = self._get_incoming(node_id, "object")             obj = self._emit_expr(obj_src) if obj_src else "?"             return f"{obj}.{n.label}"          if n.type == "binop":             left_src = self._get_incoming(node_id, "left")             right_src = self._get_incoming(node_id, "right")             left = self._emit_expr(left_src) if left_src else "?"             right = self._emit_expr(right_src) if right_src else "?"             sym = _BINOP_SYM.get(n.label, n.label)             return f"{left} {sym} {right}"          if n.type == "unaryop":             operand_src = self._get_incoming(node_id, "operand")             operand = self._emit_expr(operand_src) if operand_src else "?"             sym = _UNARYOP_SYM.get(n.label, n.label)             return f"{sym}{operand}"          if n.type == "compare":             left_src = self._get_incoming(node_id, "left")             right_src = self._get_incoming(node_id, "right")             left = self._emit_expr(left_src) if left_src else "?"             right = self._emit_expr(right_src) if right_src else "?"             cmp_sym = {                 "Eq": "==", "NotEq": "!=", "Lt": "<", "LtE": "<=",                 "Gt": ">", "GtE": ">=", "Is": "is", "IsNot": "is not",                 "In": "in", "NotIn": "not in",             }             sym = cmp_sym.get(n.label, n.label)             return f"{left} {sym} {right}"          if n.type == "call":             fn_src = self._get_incoming(node_id, "callable")             fn = self._emit_expr(fn_src) if fn_src else "?"             args = []             for e in sorted(self._incoming.get(node_id, []), key=lambda x: x.targetPort):                 if e.targetPort.startswith("arg_"):                     args.append(self._emit_expr(e.source))             return f"{fn}({', '.join(args)})"          if n.type == "subscr":             val_src = self._get_incoming(node_id, "value")             idx_src = self._get_incoming(node_id, "index")             val = self._emit_expr(val_src) if val_src else "?"             idx = self._emit_expr(idx_src) if idx_src else "?"             return f"{val}[{idx}]"          if n.type == "list_literal":             elts = [                 self._emit_expr(e.source)                 for e in sorted(self._incoming.get(node_id, []), key=lambda x: x.targetPort)                 if e.targetPort.startswith("elt_")             ]             return f"[{', '.join(elts)}]"          if n.type == "tuple_literal":             elts = [                 self._emit_expr(e.source)                 for e in sorted(self._incoming.get(node_id, []), key=lambda x: x.targetPort)                 if e.targetPort.startswith("elt_")             ]             return f"({', '.join(elts)})"          if n.type == "dict_literal":             pairs = []             edges = sorted(self._incoming.get(node_id, []), key=lambda x: x.targetPort)             keys = [e for e in edges if e.targetPort.startswith("key_")]             vals = [e for e in edges if e.targetPort.startswith("val_")]             for k, v in zip(keys, vals):                 pairs.append(f"{self._emit_expr(k.source)}: {self._emit_expr(v.source)}")             return "{" + ", ".join(pairs) + "}"          if n.type == "CodeBlockNode":             code = n.codeBlock or ""             return code.strip()          return "?"      # ════════════════════════════════════════════════════════════════════════     #  Statement generator     # ════════════════════════════════════════════════════════════════════════      def _emit_stmt(self, node_id: str) -> None:         n = self._node_map.get(node_id)         if not n:             return          if n.type == "assign":             # Detect augmented assign by label pattern: "name Op="             label = n.label             if " " in label and label.endswith("=") and not label.startswith("="):                 # Augmented assign: "x Add=" → "x += ..."                 parts = label.rsplit(" ", 1)                 target_name = parts[0]                 op_sym = _BINOP_SYM.get(parts[1].rstrip("="), parts[1].rstrip("="))                 val_src = self._get_incoming(node_id, "value")                 val = self._emit_expr(val_src) if val_src else "?"                 self._p(f"{target_name} {op_sym}= {val}")             else:                 val_src = self._get_incoming(node_id, "value")                 val = self._emit_expr(val_src) if val_src else "?"                 self._p(f"{label} = {val}")          elif n.type == "return":             val_src = self._get_incoming(node_id, "value")             if val_src:                 val = self._emit_expr(val_src)                 self._p(f"return {val}")             else:                 self._p("return")          elif n.type == "if":             test_src = self._get_incoming(node_id, "test")             test_expr = self._emit_expr(test_src) if test_src else "?"             # Determine label: "if" or "elif"             keyword = n.label if n.label in ("if", "elif") else "if"             self._p(f"{keyword} {test_expr}:", indent_delta=1)             for child in self._body_children(node_id):                 self._emit_stmt(child)             orelse = self._orelse_children(node_id)             if orelse:                 self._indent -= 1                 # Check if orelse is a single elif node                 if (                     len(orelse) == 1                     and self._node_map.get(orelse[0])                     and self._node_map[orelse[0]].type == "if"                     and self._node_map[orelse[0]].label == "elif"                 ):                     self._emit_stmt(orelse[0])                 else:                     self._p("else:", indent_delta=1)                     for child in orelse:                         self._emit_stmt(child)                     self._p("", indent_delta=-1)             else:                 self._p("", indent_delta=-1)          elif n.type == "for":             target_src = self._get_incoming(node_id, "target")             iter_src = self._get_incoming(node_id, "iter")             target_expr = self._emit_expr(target_src) if target_src else "?"             iter_expr = self._emit_expr(iter_src) if iter_src else "?"             self._p(f"for {target_expr} in {iter_expr}:", indent_delta=1)             for child in self._body_children(node_id):                 self._emit_stmt(child)             self._p("", indent_delta=-1)          elif n.type == "while":             test_src = self._get_incoming(node_id, "test")             test_expr = self._emit_expr(test_src) if test_src else "?"             self._p(f"while {test_expr}:", indent_delta=1)             for child in self._body_children(node_id):                 self._emit_stmt(child)             self._p("", indent_delta=-1)          elif n.type == "break":             self._p("break")          elif n.type == "continue":             self._p("continue")          elif n.type == "import":             asname = f" as {n.value}" if n.value else ""             self._p(f"import {n.label}{asname}")          elif n.type == "import_from":             names = ", ".join(n.value) if isinstance(n.value, list) else n.label             self._p(f"from {n.label} import {names}")          elif n.type == "function_def":             # Use real arg names from PortDef             args = [p.name for p in n.inputs]             self._p(f"def {n.label}({', '.join(args)}):", indent_delta=1)             body = self._body_children(node_id)             if body:                 for child in body:                     self._emit_stmt(child)             else:                 self._p("pass")             self._p("", indent_delta=-1)          elif n.type == "class_def":             self._p(f"class {n.label}:", indent_delta=1)             body = self._body_children(node_id)             if body:                 for child in body:                     self._emit_stmt(child)             else:                 self._p("pass")             self._p("", indent_delta=-1)          elif n.type == "CodeBlockNode":             code = n.codeBlock or ""             for line in code.split("\n"):                 stripped = line.strip()                 if stripped:                     self._p(stripped)          else:             # Standalone expression statement (call, etc.)             # Only emit if it's a call or expr type             if n.type in ("call", "compare", "binop", "unaryop", "literal", "name"):                 expr = self._emit_expr(node_id)                 if expr and expr != "?":                     self._p(expr)      # ════════════════════════════════════════════════════════════════════════     #  Main entry     # ════════════════════════════════════════════════════════════════════════      def generate(self) -> str:         """Generate Python source from IR.          Emits top-level statements sorted by source line number.         Skips:           - expression-only nodes (embedded inline in statements)           - child nodes of containers (if/for/while/function/class)         """         EXPRESSION_TYPES = {             "literal", "name", "binop", "unaryop", "attribute",             "subscr", "list_literal", "tuple_literal", "dict_literal",             "compare",         }         # Collect all node IDs that are children of a container         # (they will be emitted recursively by their parent)         all_child_ids: set[str] = set()         for n in self.graph.nodes:             all_child_ids.update(n.children)         # Also collect from body/orelse edges         for edges in self._outgoing_body.values():             for e in edges:                 all_child_ids.add(e.target)         for edges in self._outgoing_orelse.values():             for e in edges:                 all_child_ids.add(e.target)          nodes_by_line: list[tuple[int, str]] = []         for n in self.graph.nodes:             if n.type in EXPRESSION_TYPES:                 continue  # always embedded in statements             if n.id in all_child_ids:                 continue  # emitted by parent container             sm = self.ir.get("sourceMap", {}).get(n.id, {})             line = sm.get("lineStart", 999999)             nodes_by_line.append((line, n.id))         nodes_by_line.sort()          for _, nid in nodes_by_line:             self._emit_stmt(nid)          return "\n".join(self._out)   def generate(ir: dict) -> str:     """Top-level entry: IR dict → Python source string."""     return PythonGenerator(ir).generate()   def generate_file(in_path: str, out_path: str) -> str:     """Parse a JSON IR file, generate Python, and write to disk."""     import json     ir = json.loads(Path(in_path).read_text(encoding="utf-8"))     code = generate(ir)     Path(out_path).write_text(code, encoding="utf-8")     return code